<?php namespace App\Domains\Construction\Services; class ProjectService { public function create(array $data) { return \App\Domains\Construction\Models\Project::create($data); } public function update($id, array $data) { $project = \App\Domains\Construction\Models\Project::find($id); return $project ? $project->update($data) : false; } public function delete($id) { return \App\Domains\Construction\Models\Project::destroy($id); } public function list($tenantId) { return \App\Domains\Construction\Models\Project::where('tenant_id', $tenantId)->get(); } }
